-- MASEST product variants - generated by tools/build-catalog.mjs from data/catalog.seed.json. DO NOT edit by hand.
-- active=true -> public checkout may sell the variant (priced small packs only).
-- active=false -> bulk quote route or unavailable checkout variant.
on conflict (vsku) do update set
  product_sku = excluded.product_sku,
  label = excluded.label,
  gallons = excluded.gallons,
  price = excluded.price,
  active = excluded.active,
  sort = excluded.sort;
